def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 1:
            priorities[i] = np.inf
            continue
        score = 0
        for j in range(1, 11):
            if ratio < j * 0.1:
                score += (11 - j) * np.log(j + ratio) * np.sin(j + ratio)
            else:
                score += j * np.sqrt(ratio) * np.cos(j * ratio)
        if capacity % 3 == 0:
            score *= 1.15
            for k in range(1, 4):
                if (capacity + k) % 5 == 0:
                    score += np.log1p(k * ratio) * k
                else:
                    score -= np.exp(-k * ratio) * k
        elif capacity % 2 == 0:
            score *= 1.05
            for k in range(1, 3):
                if k * ratio < 0.5:
                    score += k * np.tanh(ratio * k)
                else:
                    score -= k * np.sinh(ratio / k)
        else:
            score *= 0.85
            for k in range(1, 5):
                if k % 2 == 0:
                    score += k * np.log1p(ratio * k)
                else:
                    score -= k * np.sqrt(ratio / (k + 1))
        if score < 0:
            score = abs(score) * 0.5
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        return priorities
    max_priority = np.max(finite_priorities)
    for i in range(len(priorities)):
        if not np.isfinite(priorities[i]):
            priorities[i] = max_priority * 20
    return priorities
